angular.module('starter').controller('PaymentCashController',function($scope,Dialog,PaymentCash){angular.extend($scope,{isLoading:!1});$scope.onSelect=function(){try{Dialog.confirm('Confirmation','Are you sure you want to pay with cash?',['Yes, continue','No'],'text-center','payment_cash').then(function(result){if(result){PaymentCash.fetchPayment($scope.$parent.options).then(function(result){$scope.$parent.options.onSuccess({paymentId:result.paymentId,shortName:'cash'})})}})}catch(e){console.error('Something wrong occurred, please review your Cash configuration.',e)}}});angular.module("starter").directive("paymentCash",function(){return{restrict:"E",replace:!0,scope:{options:"=?"},templateUrl:"features/payment_cash/assets/templates/l1/payment-cash.html",compile:function(element,attrs){if(!attrs.options){attrs.options={}}},controller:function($scope){}}});angular.module('starter').service('PaymentCash',function($pwaRequest){var service={};service.fetchPayment=function(options){console.log(options);return $pwaRequest.post('/paymentcash/mobile_cash/fetch-payment',{urlParams:{value_id:options.valueId},data:{options:options}})};return service});Features.insertCSS("","payment_cash")